#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, K; scanf("%d %d", &N, &K);
        char s[100005]; scanf("%s", s);
        int bestLen = 0; int bestPos = -1;
        for(int d=1; d<=26; ++d){
            int cnt[26] = {0};
            int distinct = 0, exactK = 0;
            int left = 0;
            for(int right=0; right<N; ++right){
                int idx = s[right]-'a';
                if(cnt[idx]==0) distinct++;
                if(cnt[idx]==K) exactK--;
                cnt[idx]++;
                if(cnt[idx]==K) exactK++;
                while(distinct > d){
                    int idl = s[left]-'a';
                    if(cnt[idl]==K) exactK--;
                    cnt[idl]--;
                    if(cnt[idl]==0) distinct--;
                    if(cnt[idl]==K) exactK++;
                    left++;
                }
                if(distinct==d && distinct==exactK){
                    int len = right-left+1;
                    if(len > bestLen){
                        bestLen = len; bestPos = left;
                    }
                }
            }
        }
        if(bestLen==0){
            printf("IMPOSSIBLE\n");
        }else{
            printf("%d\n", bestLen);
            for(int i=0;i<bestLen;++i) putchar(s[bestPos+i]);
            putchar('\n');
        }
    }
    return 0;
}

