#!/usr/bin/env python3
import sys

def solve_one(N, K, s):
    best_len = 0
    best_pos = -1
    for d in range(1, 27):
        cnt = [0] * 26
        distinct = exactK = 0
        left = 0
        for right, ch in enumerate(s):
            idx = ord(ch) - ord('a')
            if cnt[idx] == 0:
                distinct += 1
            if cnt[idx] == K:
                exactK -= 1
            cnt[idx] += 1
            if cnt[idx] == K:
                exactK += 1
            while distinct > d:
                idxl = ord(s[left]) - ord('a')
                if cnt[idxl] == K:
                    exactK -= 1
                cnt[idxl] -= 1
                if cnt[idxl] == 0:
                    distinct -= 1
                if cnt[idxl] == K:
                    exactK += 1
                left += 1
            if distinct == d and distinct == exactK:
                cur_len = right - left + 1
                if cur_len > best_len:
                    best_len = cur_len
                    best_pos = left
    if best_len == 0:
        return None
    return s[best_pos:best_pos + best_len]

def main():
    data = sys.stdin.read().strip().split()  # fast tokenisation
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        s = next(it)
        res = solve_one(N, K, s)
        if res is None:
            out_lines.append('IMPOSSIBLE')
        else:
            out_lines.append(str(len(res)))
            out_lines.append(res)
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

